#### 3.1 完善 API 服务

```typescript
// services/iteration.service.ts
import api from './api'

export const iterationService = {
  // 获取迭代列表
  async getIterations(params: {
    page: number
    pageSize: number
    status?: string
    startDate?: string
    endDate?: string
  }) {
    const response = await api.get('/iterations', { params })
    return response.data
  },

  // 获取迭代详情
  async getIterationDetail(id: string) {
    const response = await api.get(`/iterations/${id}`)
    return response.data
  },

  // 获取当前迭代
  async getCurrentIteration() {
    const response = await api.get('/iterations/current')
    return response.data
  },

  // 回滚迭代
  async rollbackIteration(id: string) {
    const response = await api.post(`/iterations/${id}/rollback`)
    return response.data
  },

  // 对比迭代
  async compareIterations(id1: string, id2: string) {
    const response = await api.get(`/iterations/${id1}/diff/${id2}`)
    return response.data
  }
}
```

#### 3.2 完善 Iterations.vue 页面数据加载

```vue
<!-- views/Iterations.vue -->
<script setup lang="ts">
import { ref, onMounted, computed } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { iterationService } from '@/services/iteration.service'

const iterations = ref([])
const loading = ref(false)
const searchKeyword = ref('')
const statusFilter = ref('')
const currentPage = ref(1)
const pageSize = ref(20)
const total = ref(0)

// 加载迭代列表
async function loadIterations() {
  loading.value = true
  try {
    const response = await iterationService.getIterations({
      page: currentPage.value,
      pageSize: pageSize.value,
      status: statusFilter.value || undefined
    })
    iterations.value = response.data
    total.value = response.total
  } catch (error) {
    ElMessage.error('加载迭代列表失败')
    console.error(error)
  } finally {
    loading.value = false
  }
}

// 搜索
function handleSearch() {
  currentPage.value = 1
  loadIterations()
}

// 筛选
function handleFilter() {
  currentPage.value = 1
  loadIterations()
}

// 查看详情
function viewDetail(iteration: any) {
  // 实现详情查看逻辑
  console.log('查看详情:', iteration)
}

// 回滚
async function rollback(iteration: any) {
  try {
    await ElMessageBox.confirm(
      `确定要回滚到迭代 #${iteration.iterationNumber} 吗？`,
      '确认回滚',
      { type: 'warning' }
    )

    await iterationService.rollbackIteration(iteration.id)
    ElMessage.success('回滚成功')
    loadIterations()
  } catch (error) {
    if (error !== 'cancel') {
      ElMessage.error('回滚失败')
      console.error(error)
    }
  }
}

onMounted(() => {
  loadIterations()
})
</script>
```

**验收标准**：
- ✅ 能加载和显示历史迭代
- ✅ 搜索筛选功能正常
- ✅ 详情弹窗数据完整
- ✅ 分页功能流畅
- ⚠️ 回滚功能（需后端支持）

